import 'package:flutter/material.dart'; import 'package:intl/intl.dart';
class RecentInvoiceTile extends StatelessWidget { final String number, customer; final double amount; final DateTime date; final String status; const RecentInvoiceTile({super.key, required this.number, required this.customer, required this.amount, required this.date, this.status='completed'}); Color _color(String s) { switch(s) { case 'pending': return Colors.orange; case 'completed': return Colors.green; default: return Colors.grey; } } @override Widget build(BuildContext context) => Card(margin: const EdgeInsets.symmetric(vertical:4), child: ListTile(leading: const Icon(Icons.receipt), title: Text('$number - $customer'), subtitle: Text(DateFormat.yMd().format(date)), trailing: Container(padding: const EdgeInsets.symmetric(horizontal:8, vertical:4), decoration: BoxDecoration(color: _color(status).withOpacity(0.1), borderRadius: BorderRadius.circular(12)), child: Text('${amount.toStringAsFixed(2)} ريال', style: TextStyle(color: _color(status)))))); }
